            append("userId=$userId, ")
            append("ip=$ip, ")
            append("userAgent=$userAgent")
        }
        
        if (success) {
            Timber.tag("AUTH_SUCCESS").i(logMessage)
        } else {
            Timber.tag("AUTH_FAILED").w(logMessage)
        }
